// 将文档中所有图片设置为居中对齐
var doc = Application.ActiveDocument;
var shapes = doc.Shapes;
for (var i = shapes.Count; i >= 1; i--) {
    var shape = shapes.Item(i);
    if (shape.Type === 13) { // wdInlineShapePicture
        var para = shape.Range.Paragraphs(1);
        para.Format.Alignment = 1; // wdAlignParagraphCenter
    }
}
return '已将文档中所有图片设置为居中对齐';
